<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PRAGMA mmap_size </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 536870912</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 512 MB mmap (OS-backed memory-mapped I/O)</span></span>
